// And groups predicates with the AND operator between them.
func And(predicates ...predicate.GitIdentity) predicate.GitIdentity {
	return predicate.GitIdentity(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.GitIdentity) predicate.GitIdentity {
	return predicate.GitIdentity(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.GitIdentity) predicate.GitIdentity {
	return predicate.GitIdentity(sql.NotPredicates(p))
}
